  "inlineSchema": "// Lumific Lighting - B2B/B2C Platform\n// PostgreSQL + Prisma\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nenum Role {\n  CLIENT\n  INTERIOR\n  ARCHITECT\n  SALES\n  MARKETING\n  PARTNER\n}\n\nenum ProjectMemberRole {\n  OWNER\n  MEMBER\n  VIEWER\n}\n\nenum ApprovalStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nenum OrderStatus {\n  DRAFT\n  PENDING\n  CONFIRMED\n  SHIPPED\n  DELIVERED\n  CANCELLED\n}\n\nmodel User {\n  id           String   @id @default(cuid())\n  email        String   @unique\n  passwordHash String   @map(\"password_hash\")\n  name         String?\n  role         Role     @default(CLIENT)\n  createdAt    DateTime @default(now()) @map(\"created_at\")\n  updatedAt    DateTime @updatedAt @map(\"updated_at\")\n\n  configuratorSessions ConfiguratorSession[]\n  projectMembers       ProjectMember[]\n  projectComments      ProjectComment[]\n  projectApprovals     ProjectApproval[]\n  quotes               Quote[]\n  orders               Order[]\n  trainingProgress     TrainingProgress[]\n}\n\nmodel Product {\n  id          String   @id @default(cuid())\n  name        String\n  sku         String?  @unique\n  category    String?\n  description String?\n  price       Decimal? @db.Decimal(12, 2)\n  wattage     String?\n  cct         String?\n  beamAngle   String?  @map(\"beam_angle\")\n  ipRating    String?  @map(\"ip_rating\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n  updatedAt   DateTime @updatedAt @map(\"updated_at\")\n\n  configuratorSessions ConfiguratorSession[]\n  projectPins          ProjectPin[]\n  quoteItems           QuoteItem[]\n  orderItems           OrderItem[]\n}\n\nmodel ConfiguratorSession {\n  id        String   @id @default(cuid())\n  userId    String?  @map(\"user_id\")\n  config    Json // finish, cct, beam, etc.\n  specPdf   String?  @map(\"spec_pdf\") // S3 URL\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  user      User?   @relation(fields: [userId], references: [id], onDelete: SetNull)\n  product   Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n  productId String  @map(\"product_id\")\n}\n\nmodel Project {\n  id          String   @id @default(cuid())\n  name        String\n  description String?\n  status      String   @default(\"active\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n  updatedAt   DateTime @updatedAt @map(\"updated_at\")\n\n  members   ProjectMember[]\n  pins      ProjectPin[]\n  comments  ProjectComment[]\n  approvals ProjectApproval[]\n  quotes    Quote[]\n}\n\nmodel ProjectMember {\n  id        String            @id @default(cuid())\n  projectId String            @map(\"project_id\")\n  userId    String            @map(\"user_id\")\n  role      ProjectMemberRole @default(MEMBER)\n  joinedAt  DateTime          @default(now()) @map(\"joined_at\")\n\n  project Project @relation(fields: [projectId], references: [id], onDelete: Cascade)\n  user    User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([projectId, userId])\n  @@map(\"project_members\")\n}\n\nmodel ProjectPin {\n  id        String   @id @default(cuid())\n  projectId String   @map(\"project_id\")\n  productId String   @map(\"product_id\")\n  notes     String?\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  project Project @relation(fields: [projectId], references: [id], onDelete: Cascade)\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n\n  @@unique([projectId, productId])\n  @@map(\"project_pins\")\n}\n\nmodel ProjectComment {\n  id        String   @id @default(cuid())\n  projectId String   @map(\"project_id\")\n  userId    String   @map(\"user_id\")\n  body      String\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  project Project @relation(fields: [projectId], references: [id], onDelete: Cascade)\n  user    User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"project_comments\")\n}\n\nmodel ProjectApproval {\n  id        String         @id @default(cuid())\n  projectId String         @map(\"project_id\")\n  userId    String         @map(\"user_id\")\n  status    ApprovalStatus @default(PENDING)\n  note      String?\n  createdAt DateTime       @default(now()) @map(\"created_at\")\n  updatedAt DateTime       @updatedAt @map(\"updated_at\")\n\n  project Project @relation(fields: [projectId], references: [id], onDelete: Cascade)\n  user    User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"project_approvals\")\n}\n\nmodel Quote {\n  id         String   @id @default(cuid())\n  projectId  String?  @map(\"project_id\")\n  userId     String   @map(\"user_id\")\n  clientName String?  @map(\"client_name\")\n  discount   Decimal? @db.Decimal(5, 2)\n  total      Decimal  @db.Decimal(12, 2)\n  createdAt  DateTime @default(now()) @map(\"created_at\")\n\n  project Project?    @relation(fields: [projectId], references: [id], onDelete: SetNull)\n  user    User        @relation(fields: [userId], references: [id], onDelete: Cascade)\n  items   QuoteItem[]\n  orders  Order[]\n}\n\nmodel QuoteItem {\n  id        String  @id @default(cuid())\n  quoteId   String  @map(\"quote_id\")\n  productId String  @map(\"product_id\")\n  qty       Int\n  price     Decimal @db.Decimal(12, 2)\n\n  quote   Quote   @relation(fields: [quoteId], references: [id], onDelete: Cascade)\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n\n  @@map(\"quote_items\")\n}\n\nmodel Order {\n  id        String      @id @default(cuid())\n  quoteId   String?     @map(\"quote_id\")\n  userId    String      @map(\"user_id\")\n  status    OrderStatus @default(PENDING)\n  createdAt DateTime    @default(now()) @map(\"created_at\")\n  updatedAt DateTime    @updatedAt @map(\"updated_at\")\n\n  quote Quote?      @relation(fields: [quoteId], references: [id], onDelete: SetNull)\n  user  User        @relation(fields: [userId], references: [id], onDelete: Cascade)\n  items OrderItem[]\n\n  @@map(\"orders\")\n}\n\nmodel OrderItem {\n  id        String  @id @default(cuid())\n  orderId   String  @map(\"order_id\")\n  productId String  @map(\"product_id\")\n  qty       Int\n  price     Decimal @db.Decimal(12, 2)\n\n  order   Order   @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n\n  @@map(\"order_items\")\n}\n\nmodel TrainingModule {\n  id          String   @id @default(cuid())\n  title       String\n  description String?\n  type        String? // video, quiz, pdf\n  url         String?\n  order       Int      @default(0)\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n  updatedAt   DateTime @updatedAt @map(\"updated_at\")\n\n  progress TrainingProgress[]\n}\n\nmodel TrainingProgress {\n  id        String   @id @default(cuid())\n  userId    String   @map(\"user_id\")\n  moduleId  String   @map(\"module_id\")\n  completed Boolean  @default(false)\n  score     Int?\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  user   User           @relation(fields: [userId], references: [id], onDelete: Cascade)\n  module TrainingModule @relation(fields: [moduleId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, moduleId])\n  @@map(\"training_progress\")\n}\n\nmodel TechAsset {\n  id        String   @id @default(cuid())\n  productId String?  @map(\"product_id\")\n  type      String // ies, ldt, dwg, bim, pdf\n  name      String\n  url       String // S3 URL\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  @@map(\"tech_assets\")\n}\n",
